import math

class Solution:
    def bestCoordinate(self, towers, radius):
        totals = [[0] * 101 for _ in range(101)]
        r2 = radius * radius
        for tx, ty, q in towers:
            for x in range(101):
                dx2 = (tx - x) * (tx - x)
                if dx2 > r2:
                    continue
                for y in range(101):
                    dy2 = (ty - y) * (ty - y)
                    d2 = dx2 + dy2
                    if d2 <= r2:
                        d = math.sqrt(d2)
                        totals[x][y] += math.floor(q / (1 + d))
        best = [0, 0]
        best_total = -1
        for x in range(101):
            for y in range(101):
                if totals[x][y] > best_total:
                    best_total = totals[x][y]
                    best = [x, y]
        return best

