import math

class Solution:
    def bestCoordinate(self, towers, radius):
        best = [0, 0]
        best_total = -1
        for x in range(101):
            for y in range(101):
                total = 0
                for tx, ty, q in towers:
                    d = math.hypot(tx - x, ty - y)
                    if d <= radius:
                        total += math.floor(q / (1 + d))
                if total > best_total:
                    best_total = total
                    best = [x, y]
        return best

