var bestCoordinate = function(towers, radius) {
    let best = [0, 0];
    let bestTotal = -1;
    for (let x = 0; x <= 100; x++) {
        for (let y = 0; y <= 100; y++) {
            let total = 0;
            for (const [tx, ty, q] of towers) {
                const d = Math.sqrt((tx - x) * (tx - x) + (ty - y) * (ty - y));
                if (d <= radius) {
                    total += Math.floor(q / (1 + d));
                }
            }
            if (total > bestTotal) {
                bestTotal = total;
                best = [x, y];
            }
        }
    }
    return best;
};
